import { TrendingUp, ArrowRight } from 'lucide-react';

const SAMPLES = [
  'Client has \u20B95 lakh to invest in Reliance Industries, 3-year horizon',
  'Should my client buy TCS at current levels?',
  'Client holding HDFC Bank at a loss \u2014 hold or exit?',
  'Is this a good time to enter a Nifty 50 index fund?',
];

export default function WelcomeScreen({ onSampleClick }) {
  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      justifyContent: 'center', height: '100%', minHeight: 400,
      padding: '40px 20px', animation: 'in 0.4s ease',
    }}>
      {/* Logo */}
      <div style={{
        width: 48, height: 48, borderRadius: '50%',
        background: 'var(--accent)', display: 'flex',
        alignItems: 'center', justifyContent: 'center',
        marginBottom: 20,
      }}>
        <TrendingUp size={24} color="#fff" strokeWidth={2.5} />
      </div>

      <h1 style={{
        fontSize: 22, fontWeight: 500, color: 'var(--ink)',
        marginBottom: 8, fontFamily: 'var(--f-ui)',
      }}>
        How can I help you today?
      </h1>
      <p style={{
        fontSize: 14, color: 'var(--ink-4)', marginBottom: 32,
        textAlign: 'center', maxWidth: 400, lineHeight: 1.6,
      }}>
        Ask about any stock — type a query, record a conversation, or upload an audio file.
      </p>

      {/* Sample prompts grid */}
      <div style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr',
        gap: 10, maxWidth: 600, width: '100%',
      }}>
        {SAMPLES.map((text, i) => (
          <button
            key={i}
            onClick={() => onSampleClick(text)}
            style={{
              padding: '14px 16px',
              background: 'var(--chat-bg)',
              border: '1px solid var(--rule)',
              borderRadius: 12, cursor: 'pointer',
              textAlign: 'left', fontSize: 13, color: 'var(--ink-2)',
              lineHeight: 1.5, fontFamily: 'var(--f-ui)',
              transition: 'border-color 0.15s, background 0.15s',
              display: 'flex', alignItems: 'flex-start', gap: 10,
            }}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = 'var(--rule-2)';
              e.currentTarget.style.background = 'var(--card)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = 'var(--rule)';
              e.currentTarget.style.background = 'var(--chat-bg)';
            }}
          >
            <span style={{ flex: 1 }}>{text}</span>
            <ArrowRight size={14} color="var(--ink-5)" style={{ flexShrink: 0, marginTop: 2 }} />
          </button>
        ))}
      </div>
    </div>
  );
}
